def batch_extract_invoices(doc_ids: list[str]) -> list[InvoiceData]:
    results = []
    for doc_id in doc_ids:
        # Retrieve from memory
        doc_context = client.memory.retrieve(doc_id)

        response = client.chat(
            messages=[{"role": "user", "content": f"Extract from {doc_id}: {doc_context}"}],
            tools=[extraction_schema],
            memory_context=[doc_id]
        )

        if response.tool_calls:
            results.append(InvoiceData.model_validate(response.tool_calls[0].result))
    return results

