def safe_batch_extract(doc_ids: list[str]):
    results = []
    for doc_id in doc_ids:
        extraction = client.chat(...).tool_calls[0].result

        verified = vex.verify(
            data=extraction,
            context={"doc_id": doc_id},
            checks=[
                vex.schema(InvoiceData),
                vex.field("doc_id").eq(doc_id, "Document ID mismatch"),
                vex.field_accuracy([
                    vex.field("total_amount").range(0, 1000000)
                ])
            ]
        )

        if verified.valid:
            results.append(verified.data)
    return results
